const target = document.getElementById('app');

const observer = new MutationObserver((mutations) => {
  mutations.forEach((mutation) => {
    switch (mutation.type) {
      case 'childList':
        console.log('子要素の変更:', mutation.addedNodes, mutation.removedNodes);
        break;
      case 'attributes':
        console.log('属性変更:', mutation.attributeName);
        break;
      case 'characterData':
        console.log('テキスト変更:', mutation.target.data);
        break;
    }
  });
});

observer.observe(target, {
  childList: true,      // 子要素の追加/削除
  attributes: true,     // 属性の変更
  characterData: true,  // テキストノードの変更
  subtree: true,        // 子孫要素も対象
  attributeFilter: ['class', 'style'], // 特定属性のみ
});

// 監視停止
observer.disconnect();
